const channels = $input.all().map(i => i.json).filter(ch => !ch.is_archived);
const results = [];

for (const ch of channels) {
  results.push({
    json: {
      channelId: ch.id,
      channelName: ch.name,
      memberCount: ch.num_members || 0,
      oldest: Math.floor((Date.now() - 7 * 86400000) / 1000).toString(),
      latest: Math.floor(Date.now() / 1000).toString()
    }
  });
}

return results;

const items = $input.all();
const channelStats = [];
let totalMessages = 0;
const uniqueUsers = new Set();
const userMsgCount = {};

for (const item of items) {
  const messages = item.json.messages || [];
  const channelName = item.json.channelName;
  const memberCount = item.json.memberCount;
  let channelMsgCount = 0;
  const channelUsers = new Set();

  for (const msg of messages) {
    if (msg.subtype === 'channel_join' || msg.subtype === 'channel_leave') continue;
    if (msg.bot_id) continue; // skip bot messages in stats

    channelMsgCount++;
    totalMessages++;

    if (msg.user) {
      uniqueUsers.add(msg.user);
      channelUsers.add(msg.user);
      userMsgCount[msg.user] = (userMsgCount[msg.user] || 0) + 1;
    }
  }

  if (channelMsgCount > 0) {
    channelStats.push({
      name: channelName,
      messages: channelMsgCount,
      uniquePosters: channelUsers.size,
      members: memberCount
    });
  }
}

// Sort channels by message count
channelStats.sort((a, b) => b.messages - a.messages);

// Top 5 most active channels
const topChannels = channelStats.slice(0, 5)
  .map((ch, i) => `${i + 1}. #${ch.name} — ${ch.messages} msgs (${ch.uniquePosters} people)`)
  .join('\n');

// Top 5 most active users
const topUsers = Object.entries(userMsgCount)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map((entry, i) => `${i + 1}. <@${entry[0]}> — ${entry[1]} messages`)
  .join('\n');

// Dead channels (0 messages this week, >5 members)
const allChannelNames = items.map(i => i.json.channelName);
const activeChannelNames = channelStats.map(c => c.name);
const deadChannels = items
  .filter(i => !activeChannelNames.includes(i.json.channelName) && i.json.memberCount > 5)
  .map(i => `#${i.json.channelName} (${i.json.memberCount} members)`)
  .slice(0, 5);

const weekStart = new Date(Date.now() - 7 * 86400000).toISOString().split('T')[0];
const weekEnd = new Date().toISOString().split('T')[0];

const report = `:bar_chart: *Weekly Slack Analytics*\n` +
  `:calendar: ${weekStart} → ${weekEnd}\n\n` +
  `:speech_balloon: *Total messages:* ${totalMessages}\n` +
  `:busts_in_silhouette: *Active users:* ${uniqueUsers.size}\n` +
  `:hash: *Active channels:* ${channelStats.length} / ${allChannelNames.length}\n\n` +
  `:trophy: *Most Active Channels*\n${topChannels || 'No activity'}\n\n` +
  `:star: *Most Active Users*\n${topUsers || 'No activity'}\n\n` +
  (deadChannels.length > 0 ? `:zzz: *Silent Channels (0 messages, 5+ members)*\n${deadChannels.join(', ')}` : ':white_check_mark: All channels with 5+ members had activity this week');

return [{ json: { report } }];
